"""article_3_ec2."""

from structuralcodes.codes.ec2_2004._concrete_material_properties import fctm as _fctm


def fctm_fl(fck: float, h: float) -> float:
    """The mean flexural tensile strength.

    EN 1992-1-1: 2004, Eq 3.23.

    Args:
        fck (float): The characteristic compressive strength of concrete in
            MPa.
        h (float): is the total member depth in mm

    Returns:
        float: The mean flexural tensile strength in MPa.
    """
    fctm = _fctm(fck=abs(fck))
    return max((1.6 - h / 1000) * fctm, fctm)
